import React, { useState } from 'react';
import { Layout, Typography, Menu } from 'antd';
import './App.css';
import HomePage from './components/HomePage';
import ProjectsPage from './components/ProjectsPage';
import NotesPage from './components/NotesPage';

const { Header, Content } = Layout;
const { Title, Paragraph } = Typography;

function getItem(label, key, children) {    
  return { key, children, label };    
}    
    
const items = [    
  getItem('Home', '1'),    
  getItem('Projects', '2'),    
  getItem('Notes', '3'),    
  getItem('Contact', '4'),    
];

function App() {
  const [selectedMenuItem, setSelectedMenuItem] = useState('1'); // Default selected menu item                                                                                                                     
  const handleMenuClick = ({ key }) => {                                                                                                                                                                           
    setSelectedMenuItem(key);                                                                                                                                                                                      
  }; 
  return (
    <Layout className="layout">
      <Header>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', height: '100%' }}>
        <Title level={2} style={{ margin: 0, paddingLeft: "1%", color: '#1890ff' }}>Justin Copeland</Title>
        <Menu mode="horizontal" selectedKeys={[selectedMenuItem]} defaultSelectedKeys={['1']} style={{justifyContent: 'flex-end', paddingRight: '2%'}} items={items} onClick={handleMenuClick}>
          <Menu.Item key="1">Home</Menu.Item>
          <Menu.Item key="2">Projects</Menu.Item>
          <Menu.Item key="3">Notes</Menu.Item>
          <Menu.Item key="4">Contact</Menu.Item>
        </Menu>
        </div>
      </Header>
      <Content style={{ padding: '50px', justifyContent: "center"}}>
        {selectedMenuItem === '1' && <HomePage />}
        {selectedMenuItem === '2' && <ProjectsPage />}
        {selectedMenuItem === '3' && <NotesPage />}
      </Content>
    </Layout>
  );
}

export default App;
